patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 2be3b5775292..8bf9c451d05f 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7311,6 +7311,18 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
     }
   }

+  // If the original loop contains a conditional branch with a constant condition,
+  // VPlan may prune dead edges/blocks and simplify related PHIs, which the legacy
+  // cost model doesn't account for. Treat this as an additional simplification to
+  // avoid triggering the debug assertion when the VPlan-based and legacy models
+  // pick different VFs.
+  for (BasicBlock *BB : TheLoop->blocks()) {
+    if (auto *BI = dyn_cast<BranchInst>(BB->getTerminator())) {
+      if (BI->isConditional() && isa<ConstantInt>(BI->getCondition()))
+        return true;
+    }
+  }
+
   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.

